import React, { useEffect, useState } from "react";
import { motion } from "framer-motion";
import { useLocation } from "react-router-dom";

export const UpdateDate = () => {
  const [darkMode, setDarkMode] = useState(false);
  const location = useLocation();
  function alterDarkMode() {
    setDarkMode((darkMode) => !darkMode);
    document.getElementsByClassName("mode")[0].classList.add("animate-mode");
    setTimeout(() => {
      document
        .getElementsByClassName("mode")[0]
        .classList.remove("animate-mode");
    }, 500);
  }
  useEffect(() => {
    if (darkMode) {
      document.getElementById("rootHTML").classList.add("darkMode");
      document.getElementById("navbarImage").classList.add("darkMode");
      if (location.pathname === "/")
        document.getElementById("mainImage").classList.add("darkMode");
    } else {
      document.getElementById("rootHTML").classList.remove("darkMode");
      document.getElementById("navbarImage").classList.remove("darkMode");
      if (location.pathname === "/")
        document.getElementById("mainImage").classList.remove("darkMode");
    }
    return () => {
      localStorage.clear();
    };
  });
  return (
    <div className="detail">
      <motion.button
        initial={{ opacity: 0, x: -200 }}
        animate={{ opacity: 1, x: 0 }}
        transition={{ duration: 0.5, type: "spring", stiffness: 70 }}
        className="btn mode"
        onClick={alterDarkMode}
      >
        {darkMode ? (
          <i className="fas fa-sun fa-2x" type="button"></i>
        ) : (
          <i className="fas fa-moon fa-2x" type="button"></i>
        )}
      </motion.button>
      <motion.p
        initial={{ opacity: 0, x: 200 }}
        animate={{ opacity: 1, x: 0 }}
        transition={{ duration: 0.5, type: "spring", stiffness: 70 }}
        className="updateTitle"
      >
        Last Updated on : <span className="updateInfo">11 July 2021</span>
      </motion.p>
    </div>
  );
};
