import mainLogo from "../images/VG_7.png";
import { MenuList } from "./MenuList";
import { NavLink } from "react-router-dom";
import { useState } from "react";

export const NavBar = () => {
  const [close, setClose] = useState(false);
  const menuList = MenuList.map(({ title, url, fa }, index) => {
    return (
      <li className="nav-item" key={index}>
        <NavLink
          exact
          onClick={() => {
            document
              .getElementById("navbarNavAltMarkup")
              .classList.remove("show");
            setClose(!close);
          }}
          activeClassName="active-nav-item"
          className="nav-item nav-link text-center"
          to={url}
        >
          <i className={fa}></i>&nbsp;{title}
        </NavLink>
      </li>
    );
  });
  return (
    <nav className="navbar navbar-expand-lg">
      <div className="container-fluid">
        <img
          className="navbar-brand"
          src={mainLogo}
          alt="Profile Pic"
          id="navbarImage"
        />
        <p className="navbar-brand vg">Vicky Gupta</p>
        <button
          className="navbar-toggler"
          type="button"
          data-bs-toggle="collapse"
          data-bs-target="#navbarNavAltMarkup"
          aria-controls="navbarNavAltMarkup"
          aria-expanded="false"
          aria-label="Toggle navigation"
        >
          <i className="fas fa-bars"></i>
        </button>
        <div className="collapse navbar-collapse" id="navbarNavAltMarkup">
          <div className="navbar-nav">{menuList}</div>
        </div>
      </div>
    </nav>
  );
};
