import { motion } from "framer-motion";
import { InterestList } from "./InterestList";
import { ActivityList } from "./ActivityList";
import { WebLinks } from "./WebLinks";

export const Others = () => {
  return (
    <div className="container">
      <motion.h3
        initial={{ y: -100, opacity: 0 }}
        animate={{ y: -10, opacity: 1 }}
        transition={{ duration: 0.5 }}
      >
        Others
      </motion.h3>
      <div className="others-row row">
        <motion.div
          initial={{ y: 200, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ duration: 0.6, ease: "anticipate" }}
          className="col-xxl-4 col-xl-6 col-lg-6 col-md-6 col-sm-12 col-xs-12"
        >
          <div className="card shadow">
            <div className="card-body">
              <h5 className="text-center">Interest</h5>
              <ul>
                {InterestList.map((item, i) => {
                  return (
                    <li key={i}>
                      <h5>
                        <i className="fa fa-angle-double-right"></i>
                        {" " + item}
                      </h5>
                    </li>
                  );
                })}
              </ul>
            </div>
          </div>
        </motion.div>
        <motion.div
          initial={{ y: 200, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ duration: 1, ease: "anticipate" }}
          className="col-xxl-4 col-xl-6 col-lg-6 col-md-6 col-sm-12 col-xs-12"
        >
          <div className="card shadow">
            <div className="card-body">
              <h5 className="text-center">Around the Web</h5>
              <table className="table">
                <tbody>
                  {WebLinks.map((item) => {
                    return (
                      <tr key={item.id}>
                        <td className="text-center">
                          <a rel="noreferrer" target="_blank" href={item.link}>
                            <i className={item.fontClass}></i>
                          </a>
                        </td>
                        <td>
                          <h4>
                            <a
                              rel="noreferrer"
                              target="_blank"
                              href={item.link}
                            >
                              {item.platform}
                            </a>
                          </h4>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        </motion.div>
        <motion.div
          initial={{ y: 200, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ duration: 1.4, ease: "anticipate" }}
          className="col-xxl-4 col-xl-6 col-lg-6 col-md-6 col-sm-12 col-xs-12"
        >
          <div className="card shadow">
            <div className="card-body">
              <h5 className="text-center">Activity</h5>
              <table className="table">
                <tbody>
                  {ActivityList.map((item) => {
                    return (
                      <tr key={item.id}>
                        <td className="text-center">
                          <a rel="noreferrer" target="_blank" href={item.link}>
                            <i className={item.fontClass}></i>
                          </a>
                        </td>
                        <td className="act">
                          <a rel="noreferrer" target="_blank" href={item.link}>
                            {item.act}
                          </a>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        </motion.div>
      </div>
      <br />
    </div>
  );
};
