import { SpecializationList } from "./SpecializationList";
import { CourseList } from "./CourseList";
import { GuidedProjectsList } from "./GuidedProjectsList";
import { motion } from "framer-motion";

export const CertificateRender = ({ title, cat }) => {
  let dur = 0.6;
  let list;
  if (title === "Specialization") {
    list = SpecializationList;
  } else if (title === "Course") {
    list = CourseList;
  } else if (title === "Guided Project") {
    list = GuidedProjectsList;
  }
  return (
    <>
      <motion.h4
        initial={{ x: -100, opacity: 0 }}
        animate={{ x: 0, opacity: 1 }}
        transition={{ duration: 1, ease: "anticipate" }}
        className="text-center"
      >
        {title}
      </motion.h4>
      <div className="row specialization-row">
        {list.map((item, i) => {
          if (item.category === cat) {
            return (
              <motion.div
                initial={{ opacity: 0, x: 200 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ duration: (dur = dur + 0.4), ease: "anticipate" }}
                key={i}
                className="col-xxl-4 col-xl-4 col-lg-4 col-md-6 col-sm-12 col-xs-12"
              >
                <div className="card shadow">
                  <div className="card-body text-center">
                    <p>{item.name}</p>
                    <a
                      rel="noreferrer"
                      href={item.fileLoc}
                      className="btn"
                      target="_blank"
                    >
                      View PDF
                    </a>
                  </div>
                </div>
              </motion.div>
            );
          } else {
            return "";
          }
        })}
      </div>
    </>
  );
};
