import { ProjectList } from "./ProjectList";
import { motion } from "framer-motion";

export const Projects = () => {
  let dur = 1;
  return (
    <div className="container">
      <motion.h3
        initial={{ y: -100, opacity: 0 }}
        animate={{ y: -10, opacity: 1 }}
        transition={{ duration: 0.5 }}
      >
        Projects
      </motion.h3>
      <div className="project-row row">
        {ProjectList.map((item, i) => {
          //console.log(i + " " + item);
          return (
            <motion.div
              initial={{ x: 200, opacity: 0 }}
              animate={{ x: 0, opacity: 1 }}
              transition={{
                duration: (dur = dur + 0.12),
                ease: "anticipate",
              }}
              key={i}
              className="col-xxl-3 col-xl-4 col-lg-4 col-md-6 col-sm-12 col-xs-12"
            >
              <div className="card shadow">
                <div className="card-body">
                  <div className="project-header">
                    <p className="projectName">{item.projectName}</p>
                    <p>{item.year}</p>
                  </div>
                  <p className="projectCategory">{item.projectCategory}</p>
                  <p>{item.technology}</p>
                  <div className="project-footer">
                    <a
                      rel="noreferrer"
                      target="_blank"
                      href={item.githubRepo}
                      className="btn"
                    >
                      Github Repo
                    </a>
                    <a
                      rel="noreferrer"
                      target="_blank"
                      href={
                        item.liveLink !== ""
                          ? item.liveLink
                          : item.captures !== ""
                          ? item.captures
                          : item.bbDoc !== ""
                          ? item.bbDoc
                          : "#"
                      }
                      className="btn"
                    >
                      {item.liveLink !== ""
                        ? "Live"
                        : item.captures !== ""
                        ? "Captures"
                        : item.bbDoc !== ""
                        ? "BB PDF"
                        : "#"}
                    </a>
                  </div>
                </div>
              </div>
            </motion.div>
          );
        })}
      </div>
    </div>
  );
};
