import { motion } from "framer-motion";
import { CertificateRender } from "./CertificateRender";
export const Certifications = () => {
  return (
    <div className="container">
      <motion.h3
        initial={{ y: -100, opacity: 0 }}
        animate={{ y: -10, opacity: 1 }}
        transition={{ duration: 0.5 }}
      >
        Certifications
      </motion.h3>
      <div className="row certifications-row">
        <ul className="nav nav-tabs nav-justified" id="myTab" role="tablist">
          <li className="nav-item" role="presentation">
            <button
              className="nav-link active"
              id="beginner-tab"
              data-bs-toggle="tab"
              data-bs-target="#beginner"
              type="button"
              role="tab"
              aria-controls="beginner"
              aria-selected="true"
            >
              Beginner
            </button>
          </li>
          <li className="nav-item" role="presentation">
            <button
              className="nav-link"
              id="intermediate-tab"
              data-bs-toggle="tab"
              data-bs-target="#intermediate"
              type="button"
              role="tab"
              aria-controls="intermediate"
              aria-selected="false"
            >
              Intermediate
            </button>
          </li>
          <li className="nav-item" role="presentation">
            <button
              className="nav-link"
              id="advanced-tab"
              data-bs-toggle="tab"
              data-bs-target="#advanced"
              type="button"
              role="tab"
              aria-controls="advanced"
              aria-selected="false"
            >
              Advanced
            </button>
          </li>
        </ul>
        <div className="tab-content" id="myTabContent">
          <div
            className="tab-pane fade show active"
            id="beginner"
            role="tabpanel"
            aria-labelledby="beginner-tab"
          >
            <br />
            <CertificateRender title="Specialization" cat="beginner" />
            <CertificateRender title="Course" cat="beginner" />
            <CertificateRender title="Guided Project" cat="beginner" />
          </div>
          <div
            className="tab-pane fade"
            id="intermediate"
            role="tabpanel"
            aria-labelledby="intermediate-tab"
          >
            <br />
            <CertificateRender title="Specialization" cat="intermediate" />
            <CertificateRender title="Course" cat="intermediate" />
            <CertificateRender title="Guided Project" cat="intermediate" />
          </div>
          <div
            className="tab-pane fade"
            id="advanced"
            role="tabpanel"
            aria-labelledby="advanced-tab"
          >
            <br />
            <CertificateRender title="Course" cat="advanced" />
          </div>
        </div>
      </div>
    </div>
  );
};
